def request_quota_increase(
    subscription_id: str,
    location: str,
    vm_family: str,
    requested_vcpus: int,
    token: str,
) -> dict:
    """
    Open a quota increase support case for VM cores.
    Uses the Quota REST API (preview) which avoids the support ticket flow for eligible quotas.
    """
    import requests

    # Preferred path: Quota API (no support case needed for many quota types)
    quota_url = (
        f"https://management.azure.com/subscriptions/{subscription_id}"
        f"/providers/Microsoft.Quota/quotas/{vm_family.replace(' ', '_')}"
        f"?location={location}&api-version=2023-02-01"
    )
    body = {
        "properties": {
            "limit": {
                "limitObjectType": "LimitValue",
                "value": requested_vcpus,
            },
            "name": {"value": vm_family},
            "resourceType": "dedicated",
        }
    }
    resp = requests.patch(
        quota_url,
        json=body,
        headers={"Authorization": f"Bearer {token}"},
        timeout=30,
    )
    if resp.status_code == 202:
        # Async quota increase accepted
        operation_url = resp.headers.get("Azure-AsyncOperation") or resp.headers.get("Location")
        print(f"Quota increase accepted — polling: {operation_url}")
        return {"status": "accepted", "operation_url": operation_url}
    elif resp.status_code == 200:
        print("Quota increase applied immediately.")
        return resp.json()
    else:
        print(f"Quota API declined ({resp.status_code}) — must open support case manually.")
        return {"status": "requires_support_case", "detail": resp.text}

