import requests
from azure.identity import DefaultAzureCredential

def list_subscriptions_in_mg(mg_id: str, token: str) -> list[dict]:
    """List all subscriptions under a management group recursively."""
    url = (
        f"https://management.azure.com/providers/Microsoft.Management"
        f"/managementGroups/{mg_id}/descendants"
        f"?api-version=2020-05-01&$filter=type eq 'subscriptions'"
    )
    resp = requests.get(url, headers={"Authorization": f"Bearer {token}"}, timeout=30)
    resp.raise_for_status()
    return [
        {"id": item["name"], "display_name": item["properties"]["displayName"]}
        for item in resp.json().get("value", [])
    ]

def get_support_plan_type(subscription_id: str, token: str) -> str:
    """Return the active support plan name for a subscription."""
    url = (
        f"https://management.azure.com/subscriptions/{subscription_id}"
        f"/providers/Microsoft.Support/supportPlanTypes"
        f"?api-version=2021-06-01-preview"
    )
    try:
        resp = requests.get(url, headers={"Authorization": f"Bearer {token}"}, timeout=15)
        if resp.status_code == 404:
            return "basic"
        resp.raise_for_status()
        plans = resp.json().get("value", [])
        if not plans:
            return "basic"
        return plans[0]["name"].lower()
    except Exception:
        return "unknown"

PAID_PLANS = {"developer", "standard", "professionaldirect", "premier", "unified"}

def audit_support_plans(mg_id: str) -> list[dict]:
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token

    subs = list_subscriptions_in_mg(mg_id, token)
    results = []
    for sub in subs:
        plan = get_support_plan_type(sub["id"], token)
        results.append({
            "subscription_id": sub["id"],
            "name": sub["display_name"],
            "plan": plan,
            "compliant": plan in PAID_PLANS,
        })
    return results

report = audit_support_plans("my-management-group")
non_compliant = [r for r in report if not r["compliant"]]
print(f"Non-compliant subscriptions ({len(non_compliant)}/{len(report)}):")
for r in non_compliant:
    print(f"  {r['subscription_id']} ({r['name']}) — {r['plan']}")
